// CQRS Command Handler — CreateBooking
@CommandHandler(CreateBookingCommand)
export class CreateBookingHandler {
  constructor(
    private bookingRepo: BookingRepository,
    private eventBus: EventBus,
  ) {}

  async execute(command: CreateBookingCommand) {
    const booking = await this.bookingRepo.create(command.dto);
    this.eventBus.publish(new BookingCreatedEvent(booking));
    return booking;
  }
}

// Event-driven domain logic — decouple side effects
@OnEvent('task.moved')
async handleTaskMoved(event: TaskMovedEvent) {
  // Notify all workspace members via WebSocket
  this.gateway.broadcastToWorkspace(event.workspaceId, {
    type: 'task:moved',
    payload: event,
  });
  // Audit log in background queue
  await this.auditQueue.add('log', {
    action: 'task.moved',
    ...event,
  });
}
